import{_ as e,o as a,c as i,ag as n}from"./chunks/framework.YaIgwL5o.js";const c=JSON.parse('{"title":"Animations & Fragments","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/animations.md","filePath":"tutorials/animations.md"}'),o={name:"tutorials/animations.md"};function r(l,t,s,m,d,h){return a(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="animations-fragments" tabindex="-1">Animations &amp; Fragments <a class="header-anchor" href="#animations-fragments" aria-label="Permalink to &quot;Animations &amp; Fragments&quot;">​</a></h1><h2 id="entry-animations" tabindex="-1">Entry animations <a class="header-anchor" href="#entry-animations" aria-label="Permalink to &quot;Entry animations&quot;">​</a></h2><p>Make elements animate in when a slide becomes active.</p><ol><li>Select an element.</li><li>In the right panel, find <strong>Animation</strong> &gt; <strong>Entry Animation</strong>.</li><li>Choose a preset:</li></ol><table tabindex="0"><thead><tr><th>Animation</th><th>Description</th></tr></thead><tbody><tr><td>Fade In</td><td>Simple opacity fade</td></tr><tr><td>Fade Up/Down/Left/Right</td><td>Fade + directional slide</td></tr><tr><td>Zoom In / Zoom Out</td><td>Scale from smaller/larger</td></tr><tr><td>Slide Up/Down/Left/Right</td><td>Full offscreen slide</td></tr><tr><td>Flip X / Flip Y</td><td>3D rotation flip</td></tr></tbody></table><ol start="4"><li>Set <strong>Duration</strong> (ms) and <strong>Delay</strong> (ms).</li></ol><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/animations.html" style="width:100%;height:200px;border:none;"></iframe></div><h2 id="animation-timeline" tabindex="-1">Animation timeline <a class="header-anchor" href="#animation-timeline" aria-label="Permalink to &quot;Animation timeline&quot;">​</a></h2><p>For fine-grained control over animation ordering:</p><ol><li>Click the <strong>Timeline</strong> button in the top toolbar.</li><li>A timeline panel opens at the bottom showing all animated elements.</li><li>Drag elements to reorder their sequence.</li><li>Adjust delays to stagger entry times.</li></ol><h2 id="fragments" tabindex="-1">Fragments <a class="header-anchor" href="#fragments" aria-label="Permalink to &quot;Fragments&quot;">​</a></h2><p>Fragments let you reveal elements step-by-step within a single slide (advancing with arrow keys or clicks).</p><ol><li>Select an element.</li><li>In the right panel, enable <strong>Fragment</strong>.</li><li>Choose the fragment animation: fade-in, fade-up, highlight, etc.</li><li>Set the <strong>fragment index</strong> to control the reveal order (lower numbers appear first).</li></ol><p>In present mode, each click or arrow press reveals the next fragment before advancing to the next slide.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Combine fragments with entry animations for maximum impact — the fragment controls <em>when</em> the element appears, and the entry animation controls <em>how</em> it appears.</p></div>',16)])])}const g=e(o,[["render",r]]);export{c as __pageData,g as default};
